import React, { useState } from "react";

const Profile = () => {
  // ✅ localStorage-லிருந்து user data எடுக்கிறோம்
  const storedUser = JSON.parse(localStorage.getItem("user") || "{}");

  const [profile, setProfile] = useState({
    name:   storedUser.name  || "",
    email:  storedUser.email || "",
    phone:  storedUser.phone || "",
    role:   storedUser.role  || "",
    bio:    storedUser.bio   || "",
    skills: storedUser.skills || "",
  });

  const [saving, setSaving]   = useState(false);
  const [success, setSuccess] = useState("");

  const handleChange = (e) =>
    setProfile({ ...profile, [e.target.name]: e.target.value });

  const saveProfile = () => {
    setSaving(true);
    // Save to localStorage (backend profile route இல்லாததால்)
    const updated = { ...storedUser, ...profile };
    localStorage.setItem("user", JSON.stringify(updated));
    setTimeout(() => {
      setSaving(false);
      setSuccess("Profile saved successfully!");
      setTimeout(() => setSuccess(""), 3000);
    }, 600);
  };

  return (
    <div className="bg-gray-50 min-h-screen p-8">
      <div className="max-w-2xl mx-auto">
        <h1 className="text-2xl font-bold text-gray-800 mb-1">My Profile</h1>
        <p className="text-gray-500 mb-6 text-sm">Manage your account information</p>

        {success && (
          <div className="bg-green-50 border border-green-200 text-green-700 px-4 py-3 rounded-lg mb-5 text-sm">
            ✅ {success}
          </div>
        )}

        <div className="bg-white rounded-2xl shadow p-6 border border-gray-100">

          {/* AVATAR */}
          <div className="flex items-center gap-4 mb-6 pb-6 border-b">
            <div className="w-16 h-16 bg-teal-600 text-white rounded-full flex items-center justify-center text-2xl font-bold">
              {profile.name?.charAt(0)?.toUpperCase() || "?"}
            </div>
            <div>
              <h2 className="text-lg font-bold text-gray-800">{profile.name}</h2>
              <p className="text-gray-500 text-sm">{profile.email}</p>
              <span className="bg-teal-100 text-teal-700 text-xs px-2 py-0.5 rounded-full capitalize font-medium">
                {profile.role}
              </span>
            </div>
          </div>

          {/* FORM */}
          <div className="grid grid-cols-2 gap-4 mb-4">
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-1">Full Name</label>
              <input name="name" value={profile.name} onChange={handleChange}
                className="w-full border border-gray-300 px-3 py-2 rounded-lg text-sm focus:ring-2 focus:ring-teal-500 outline-none" />
            </div>
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-1">Email</label>
              <input name="email" value={profile.email} onChange={handleChange}
                className="w-full border border-gray-300 px-3 py-2 rounded-lg text-sm focus:ring-2 focus:ring-teal-500 outline-none" />
            </div>
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-1">Phone</label>
              <input name="phone" value={profile.phone} onChange={handleChange}
                placeholder="+91 98765 43210"
                className="w-full border border-gray-300 px-3 py-2 rounded-lg text-sm focus:ring-2 focus:ring-teal-500 outline-none" />
            </div>
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-1">Role</label>
              <input name="role" value={profile.role} disabled
                className="w-full border border-gray-200 px-3 py-2 rounded-lg text-sm bg-gray-50 text-gray-400 capitalize" />
            </div>
          </div>

          <div className="mb-4">
            <label className="block text-sm font-medium text-gray-700 mb-1">Skills <span className="text-gray-400">(comma separated)</span></label>
            <input name="skills" value={profile.skills} onChange={handleChange}
              placeholder="React, Node.js, MySQL..."
              className="w-full border border-gray-300 px-3 py-2 rounded-lg text-sm focus:ring-2 focus:ring-teal-500 outline-none" />
          </div>

          <div className="mb-6">
            <label className="block text-sm font-medium text-gray-700 mb-1">Bio</label>
            <textarea name="bio" value={profile.bio} onChange={handleChange} rows={3}
              placeholder="Tell clients about yourself, your experience and expertise..."
              className="w-full border border-gray-300 px-3 py-2 rounded-lg text-sm focus:ring-2 focus:ring-teal-500 outline-none resize-none" />
          </div>

          <button onClick={saveProfile} disabled={saving}
            className="bg-teal-600 hover:bg-teal-700 text-white px-6 py-2 rounded-lg text-sm font-medium transition disabled:opacity-50">
            {saving ? "Saving..." : "Save Profile"}
          </button>
        </div>
      </div>
    </div>
  );
};

export default Profile;
